import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import { useEffect } from 'react';
import { cn } from '@/lib/utils';
import { env } from '@/config/env';
import type { LatLng, MapMarker } from '@/types/common';

delete (L.Icon.Default.prototype as Record<string, unknown>)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

function FlyTo({ center }: { center?: LatLng }) {
  const map = useMap();
  useEffect(() => {
    if (center) map.flyTo([center.lat, center.lng], map.getZoom());
  }, [center, map]);
  return null;
}

interface AppMapProps {
  center?: LatLng;
  zoom?: number;
  markers?: MapMarker[];
  className?: string;
  onMarkerClick?: (marker: MapMarker) => void;
}

export function AppMap({ center = { lat: 41.2995, lng: 69.2401 }, zoom = 12, markers = [], className, onMarkerClick }: AppMapProps) {
  return (
    <div className={cn('rounded-lg overflow-hidden border border-border bg-white dark:bg-slate-950', className)}>
      <MapContainer center={[center.lat, center.lng]} zoom={zoom} style={{ height: '100%', width: '100%', minHeight: 300 }}>
        <TileLayer url={env.MAP_TILE_URL} attribution='&copy; OpenStreetMap' />
        <FlyTo center={center} />
        {markers.map((marker) => (
          <Marker key={marker.id} position={[marker.lat, marker.lng]} eventHandlers={{ click: () => onMarkerClick?.(marker) }}>
            {(marker.title || marker.description) && (
              <Popup>
                {marker.title && <strong className="block font-semibold text-foreground">{marker.title}</strong>}
                {marker.description && <span className="text-sm text-foreground">{marker.description}</span>}
              </Popup>
            )}
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
}

